-- Enrichment marathon batch: Boopos, BoostUp, BootstrapCDN, BorgBase, Bottles, bottom, Boulevard, Box

-- ── Boopos ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Boopos was a fintech lender that provided acquisition financing for buying online businesses such as e-commerce stores, Amazon FBA brands, and SaaS companies; it was acquired by Founderpath in 2025 and no longer accepts new loan applications directly.$q$, short_description),
  pricing_model = COALESCE($q$custom$q$, pricing_model),
  starting_price = COALESCE($q$Historical acquisition loan rates of 17% to 23% APR; new applications now route through Founderpath$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE($q$Small team (acquired by Founderpath in 2025)$q$, company_size),
  headquarters = COALESCE($q$Miami, Florida, United States (with a Madrid, Spain office)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Boopos: Acquisition Financing for Online Businesses$q$, seo_title),
  seo_meta_description = COALESCE($q$Boopos provided loans to acquire e-commerce and SaaS businesses. Now part of Founderpath. See how its financing, rates, and terms worked.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Boopos was a fintech company founded in 2020, headquartered in Miami, Florida with an additional office in Madrid, Spain, that specialized in acquisition financing for buyers of online businesses, including e-commerce stores, Amazon FBA brands, SaaS companies, and other subscription or content-based digital businesses. Its core product was a revenue-based acquisition loan that could fund up to 80 percent of a purchase price, structured as non-dilutive debt that did not require personal guarantees from the borrower, distinguishing it from traditional bank loans or equity investment. Boopos advertised a fast underwriting process, claiming it could evaluate an online business and issue a term sheet within 2 to 3 business days, with funding available within 7 days of an executed letter of intent. Historical interest rates on Boopos loans ranged from approximately 17 to 23 percent APR. The company also offered adjacent services such as business valuations and advisory calls to support buyers navigating acquisitions. Boopos raised a total of roughly 263 million dollars across debt facilities and equity, including a 30 million dollar Series Seed round in February 2022 led by Fasanara and a 58 million dollar Series A round led by Bonsai Partners later that year. In March 2025, Boopos was acquired by Founderpath, a financing platform for SaaS founders, in an eight-figure deal. As a direct result of that acquisition, Boopos stopped accepting new loan applications; its website now directs prospective borrowers to explore financing options through Founderpath instead. Existing Boopos borrowers at the time of the acquisition continued to have their loans serviced under original terms, with no immediate changes to payments or support. Because Boopos no longer originates new acquisition loans as a standalone brand, it is best understood today as a discontinued direct-lending product whose technology, underwriting expertise, and loan book were absorbed into Founderpath's broader SaaS financing offering.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '4d4e8ad2-0a77-49b7-a93f-86b5b0d11355';

