-- ── BoostUp ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$BoostUp is an AI-powered revenue intelligence and forecasting platform that helps B2B sales teams unify pipeline analytics, deal inspection, and conversation intelligence to predict revenue outcomes more accurately.$q$, short_description),
  pricing_model = COALESCE($q$custom$q$, pricing_model),
  starting_price = COALESCE($q$From approximately 79 dollars per user per month, with final pricing custom-quoted based on users and modules$q$, starting_price),
  founded_year = COALESCE(2018, founded_year),
  company_size = COALESCE($q$51-200 employees$q$, company_size),
  headquarters = COALESCE($q$Santa Clara, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$BoostUp: AI Revenue Intelligence and Forecasting$q$, seo_title),
  seo_meta_description = COALESCE($q$BoostUp is an AI revenue intelligence platform for B2B sales teams, unifying forecasting, pipeline analytics, and deal inspection in one place.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$BoostUp, operating as BoostUp.ai, is an AI-powered revenue operations and intelligence platform founded in 2018 and headquartered in Santa Clara, California, with roughly 51 to 200 employees. The platform is built for B2B revenue teams, particularly mid-market and enterprise sales organizations, that need highly accurate, multi-dimensional forecasting across complex revenue models such as SaaS subscriptions, consumption-based pricing, product-led growth motions, and renewals. BoostUp's core product, marketed as its Revenue Command Center, unifies several functions that are traditionally handled by separate point solutions: AI-driven machine forecasting that models pipeline data to predict close rates and revenue outcomes, advanced pipeline analytics and waterfall reporting that track how deals move and slip across a quarter, deal and engagement risk scoring that flags at-risk opportunities before they are lost, and AI-guided deal inspection that surfaces coaching insights for sales managers during pipeline reviews. The platform also includes RevBI, a self-service revenue business intelligence layer that lets revenue operations teams build custom reports and dashboards without relying on data teams, native conversation intelligence that analyzes sales calls, and BoostBot, an AI agent layer that generates alerts and next-best-action recommendations for reps and managers. Automatic activity capture pulls data from email, calendar, and conferencing tools to keep CRM records current without manual entry, and mobile apps let reps and managers update deals and submit forecasts away from their desks. BoostUp positions itself as a competitor to other revenue intelligence platforms such as Clari and Gong's forecasting tools, differentiating on its emphasis on multi-dimensional, model-driven forecasting accuracy for complex go-to-market motions rather than a single linear sales pipeline. Pricing is not fully transparent; third-party sources report a published starting price near 79 dollars per user per month with a free trial, but actual cost depends on the number of users, the specific modules deployed such as forecasting versus RevBI, and the size of the deployment, meaning most customers receive a custom quote through BoostUp's sales team rather than self-service checkout.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '27fefb6a-7a24-4693-81d8-725996b762cc';

