-- ── BootstrapCDN ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$BootstrapCDN is a free content delivery network that hosts the Bootstrap CSS and JavaScript framework along with Font Awesome icons, now operated and maintained by jsDelivr.$q$, short_description),
  pricing_model = COALESCE($q$free$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2012, founded_year),
  company_size = COALESCE($q$Small open-source team (operated by jsDelivr)$q$, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$BootstrapCDN: Free CDN for Bootstrap and Font Awesome$q$, seo_title),
  seo_meta_description = COALESCE($q$BootstrapCDN is a free CDN hosting the Bootstrap framework and Font Awesome icons, now powered and maintained by jsDelivr infrastructure.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$BootstrapCDN is a free content delivery network dedicated to hosting the Bootstrap CSS and JavaScript framework, along with the Font Awesome icon library, so developers can include them in web projects via a hosted link instead of downloading and self-hosting the files. It was launched in 2012 by David Henzel and Justin Dorfman while working at MaxCDN, and for years operated as MaxCDN's flagship open-source project, serving Bootstrap assets to a large share of the web's front-end developers. Around 2021, BootstrapCDN transitioned to be operated and maintained by jsDelivr, a separate open-source CDN project; jsDelivr took over full ownership of the bootstrapcdn.com domain and folded BootstrapCDN's infrastructure into its own network. As part of that transition, legacy hostnames that developers had embedded in millions of existing websites, including stackpath.bootstrapcdn.com and maxcdn.bootstrapcdn.com, were migrated to new backing infrastructure without requiring any action from site owners, preserving backward compatibility for old code snippets. Today the service's traffic and DNS are handled by Cloudflare, origin storage sits on Amazon S3, and BunnyCDN provides origin shielding along with URL rewriting and HTTP header handling. jsDelivr states it will continue to support all previously issued BootstrapCDN hostnames and URLs indefinitely, meaning old integration snippets referencing bootstrapcdn.com or its legacy subdomains keep working. BootstrapCDN itself charges nothing to use; it is funded and maintained as an open infrastructure project rather than a commercial product, and is largely maintained by a small team associated with jsDelivr, including maintainer Dmitriy Akulov. The core use case for BootstrapCDN has not changed since 2012: developers add a script or link tag pointing at BootstrapCDN's hosted files to get Bootstrap's CSS grid, components, and JavaScript plugins, or Font Awesome's icon set, without managing local copies, benefiting from CDN caching, browser cache sharing across sites that use the same public CDN URL, and geographically distributed edge servers for faster load times.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '43eb1f18-f8c1-4055-9bd9-67c2673345ba';

