-- ── BorgBase ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$BorgBase is a backup hosting service purpose-built for BorgBackup and Restic, the open-source deduplicating backup tools, offering encrypted repository storage for developers and technical users.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (10 GB, 2 repositories); paid plans from 24 dollars per year for 250 GB$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE($q$Small team, operated by Peakford Ltd$q$, company_size),
  headquarters = COALESCE($q$Naxxar, Malta$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$BorgBase: Hosting for BorgBackup and Restic Repositories$q$, seo_title),
  seo_meta_description = COALESCE($q$BorgBase offers secure, encrypted hosting for BorgBackup and Restic repositories, with a free 10 GB tier and paid plans from 24 dollars a year.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$BorgBase is a backup hosting service built specifically around BorgBackup and Restic, two popular open-source deduplicating backup tools favored by developers, sysadmins, and technically inclined home users. Rather than being a general-purpose cloud storage provider, BorgBase provides remote repository hosting purpose-built for how Borg and Restic work, including support for append-only mode that protects backups from being altered or deleted even if a client machine is compromised by ransomware, end-to-end encryption where BorgBase itself cannot read the backed-up data, two-factor authentication for account security, and monitoring and alerting via email, Pushover, or webhook so users know if a scheduled backup fails to run. The service is operated by Peakford Ltd, a small company based in Naxxar, Malta, that also operates PikaPods, a managed hosting service for self-hosted open-source applications; the team describes itself as having more than a decade of experience running boutique web and backup services. BorgBase offers a permanently free tier with 10 GB of storage and 2 repositories, making it accessible for individuals to try before committing to a paid plan. Paid plans are tiered by storage: a Small plan offers 250 GB for 24 dollars per year, a Medium plan offers 1 TB for 90 dollars per year, and a Large plan offers 2 TB for 165 dollars per year or 17 dollars per month, with all paid tiers including unlimited or near-unlimited repositories depending on the tier and the choice of EU or US hosting regions. Beyond the base storage included in a plan, BorgBase allows flexible overage usage up to roughly three times the plan's base storage, billed only for what is actually used, and the company does not charge separately for uploads, downloads, or API calls, which distinguishes it from many general-purpose cloud storage providers that charge for egress. BorgBase also offers a 30-day refund window on annual plans and provides API access for automating repository management. Because it is narrowly focused on the Borg and Restic ecosystem, BorgBase is primarily used by developers, sysadmins, and privacy-conscious individuals who already use Borg or Restic locally and need a reliable, encrypted, off-site destination for their backup repositories rather than a general file-sync or cloud-drive product.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '4ecc6a92-bd84-46ac-ae4b-7a99940eda7f';

