-- ── Bottles ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Bottles is a free, open-source Linux application that provides a graphical interface for creating and managing isolated Wine environments, making it easier to run Windows software and games on Linux.$q$, short_description),
  pricing_model = COALESCE($q$free$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE($q$Open-source community project (bottlesdevs)$q$, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Bottles: Run Windows Apps and Games on Linux$q$, seo_title),
  seo_meta_description = COALESCE($q$Bottles is a free, open-source tool that lets you run Windows software and games on Linux using isolated, sandboxed Wine environments.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Bottles is a free and open-source Linux application, first made public around 2020, that provides a graphical, user-friendly interface for creating and managing isolated Wine prefixes, commonly called bottles, so that Windows software and games can run on Linux without requiring users to master Wine's command-line configuration directly. The project is maintained by the bottlesdevs organization on GitHub, with core contributors including Mirko Brombin, Francesco Masala, and Pietro Di Caprio; Brombin, an Italian UX designer who also created the VanillaOS Linux distribution, is closely associated with founding the project. Bottles is written in Python using the GTK toolkit and is licensed under the GPL-3.0 open-source license. Functionally, Bottles lets a user create a separate, isolated environment for each Windows application or game, automatically handling the download and installation of the appropriate Wine runner version and common Windows dependencies such as DirectX or .NET components, and organizing each environment so that different applications do not interfere with one another. A key architectural feature is sandboxing: Bottles is designed to confine each Windows application inside its environment, limiting what it can access on the host Linux system, which the project frames as both an organizational convenience and a security benefit that can help contain malware or misbehaving Windows software. The developers strongly recommend installing Bottles via Flatpak, distributed through Flathub under the package ID com.usebottles.bottles, because the Flatpak build is the only distribution method that provides Bottles' full sandboxing capability; other packaging formats exist but do not offer the same isolation guarantees. Bottles is commonly used by Linux gamers who want to run Windows-only games that lack native Linux ports or a Proton-based Steam integration, as well as by users who need specific Windows productivity or creative applications that have no Linux equivalent. As a fully open-source project with no paid tiers, Bottles is free for anyone to download, use, and modify, and its source code is publicly available on GitHub for community contribution.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'f6982bed-77ea-4c1c-86ae-f110f934bb26';

