-- ── bottom ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$bottom, often invoked as btm, is a free, open-source, cross-platform terminal system resource monitor written in Rust that displays real-time CPU, memory, disk, network, and process information.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE($q$Open-source project maintained by Clement Tsang$q$, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$bottom (btm): Rust Terminal System Monitor$q$, seo_title),
  seo_meta_description = COALESCE($q$bottom, run as btm, is a free open-source Rust terminal system monitor showing real-time CPU, memory, disk, and network graphs, cross-platform.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$bottom, distributed as the command-line binary btm, is a free and open-source, cross-platform system resource monitor for the terminal, written in the Rust programming language and maintained by developer Clement Tsang. It is designed as an alternative to classic Unix monitoring tools like top and htop, and its author cites gotop, gtop, and htop as direct inspirations for its design and feature set. bottom runs on Linux, macOS, and Windows, making it more broadly cross-platform than many terminal monitors that are Unix-only. The project is published under the MIT license and is available through Rust's package manager via cargo install bottom, as well as through numerous system package managers across the platforms it supports. Functionally, bottom presents a graphical, panel-based terminal interface showing real-time data: CPU usage per core and in aggregate, RAM and swap usage, network input and output throughput with support for zooming in and out on historical graphs, disk capacity and usage across mounted volumes, temperature sensor readings, and battery status on supported hardware. It also includes a searchable, sortable process list similar to htop, letting users filter, sort, and terminate processes directly from the terminal interface. A defining characteristic of bottom is its emphasis on customization: users can configure layouts, colors, and displayed widgets through a configuration file, tailoring which metrics appear and how they are arranged on screen. Because it is written in Rust, bottom is designed to have low memory overhead and high performance, aiming to run comfortably even on lower-specification machines where a heavier monitoring tool might itself consume noticeable resources. The project has attracted a substantial following in the developer and systems administration community, with its GitHub repository, maintained under the ClementTsang/bottom namespace, having accumulated more than 22,000 stars. As a fully open-source, MIT-licensed project, bottom has no pricing, subscription, or paid tier of any kind; it is entirely free to install and use.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '73ac7167-1ba7-4e44-bbf8-dbdbcad06d99';

