-- ── Boulevard ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Boulevard is a business management and booking platform built specifically for salons, spas, and med spas, covering appointment scheduling, point of sale, payments, and client marketing.$q$, short_description),
  pricing_model = COALESCE($q$subscription$q$, pricing_model),
  starting_price = COALESCE($q$159 dollars per month per location (Essentials plan, billed annually)$q$, starting_price),
  founded_year = COALESCE(2016, founded_year),
  company_size = COALESCE($q$201-500 employees$q$, company_size),
  headquarters = COALESCE($q$Los Angeles, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Boulevard: Booking and Management Software for Salons$q$, seo_title),
  seo_meta_description = COALESCE($q$Boulevard is booking and business management software for salons, spas, and med spas, covering scheduling, payments, POS, and marketing.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Boulevard, marketed at joinblvd.com, is a business management and booking platform built specifically for appointment-based self-care businesses including hair salons, spas, and medical spas. It was founded in 2016 in Los Angeles by Matt Danna, who serves as CEO, and Sean Stavropoulos, the CTO, both former coworkers at Fullscreen, and the company remains headquartered in Los Angeles. Boulevard began as an online booking platform and has expanded into a full AI-driven software-as-a-service suite covering appointment scheduling, point-of-sale checkout, integrated payment processing, personalized text and email marketing, client relationship management, and reporting, aimed at helping self-care businesses run both front-desk operations and client retention marketing from one system. The company has raised approximately 188 million dollars in total funding since its founding, including a 70 million dollar Series C round, and most recently an 80 million dollar Series D round completed in July 2025 that valued the company at roughly 800 million dollars post-money, with investors including Index Ventures, VMG Partners, BoxGroup, Bonfire Ventures, and Ludlow Ventures; Boulevard reported roughly a 500 percent increase in revenue over the three years leading up to that raise. Boulevard's pricing is tiered by business type and location. For standard salons and spas, the Essentials plan costs 176 dollars per month per location or 159 dollars per month if billed annually, with 100 free two-way text messages and 500 free email blasts included per month; the Premier plan costs 293 dollars per month or 263 dollars per month annually with 250 free texts; and the Prestige plan costs 410 dollars per month or 369 dollars per month annually with 2,500 free texts. For medical spas, Boulevard offers separate Aesthetics-branded bundles: an Aesthetics Starter Bundle at 410 dollars per month, or 369 dollars annually, and an Aesthetics Bundle at 468 dollars per month, or 421 dollars annually. Boulevard also processes payments directly through its platform, charging 2.65 percent plus 15 cents per card-present transaction and 3.65 percent plus 15 cents per card-not-present transaction, and sells its own Boulevard Duo card reader hardware for 149 dollars. There is no free plan or free trial publicly listed; prospective customers typically go through a sales demo before subscribing. Boulevard also offers a dedicated product for multi-location salon and spa franchises, reflecting its focus on scaling operations across many locations rather than only single-location shops.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
