-- ── Box ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Box is a publicly traded (NYSE: BOX) enterprise cloud content management platform that lets organizations securely store, share, collaborate on, and govern files and business content, now increasingly built around AI-powered content workflows.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$5 dollars per user per month (Business Starter plan, billed annually, 3-user minimum)$q$, starting_price),
  founded_year = COALESCE(2005, founded_year),
  company_size = COALESCE($q$Approximately 2,912 employees (as of fiscal year 2026)$q$, company_size),
  headquarters = COALESCE($q$Redwood City, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Box: Enterprise Cloud Content Management Platform$q$, seo_title),
  seo_meta_description = COALESCE($q$Box (NYSE: BOX) is an enterprise cloud content management platform for secure file storage, sharing, and AI-powered content workflows.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Box, Inc. is a publicly traded enterprise cloud content management company, listed on the New York Stock Exchange under the ticker BOX, founded in 2005 by Aaron Levie and Dylan Smith and headquartered in Redwood City, California. Levie remains CEO and Smith has served as CFO. Box went public via IPO in January 2015. The company describes its category as Intelligent Content Management, or ICM, positioning its platform beyond simple file storage into secure content collaboration, workflow automation, e-signature through Box Sign, security and compliance controls through Box Shield and Box Governance, and increasingly AI-powered features branded as Box AI that let organizations extract insights, summarize documents, and automate processes across stored content. For its fiscal year 2026, ending January 31, 2026, Box reported revenue of approximately 1.18 billion dollars, representing roughly 8 percent year-over-year growth. The company had approximately 2,912 employees as of the end of fiscal 2026, an increase of about 102 employees, or 3.63 percent, from the prior year. Box serves a large enterprise customer base, with over 100,000 businesses using the platform globally and roughly 68 percent of the Fortune 500 among its customers; it counts nearly 2,000 customers paying at least 100,000 dollars annually, up 8 percent year over year, and its newer Enterprise Advanced tier accounts for roughly 10 percent of total revenue, reflecting a push toward higher-value AI and governance features. Box's pricing is structured across five tiers: Business Starter at 5 dollars per user per month, Business at 15 dollars, Business Plus at 25 dollars, and Enterprise at 35 dollars per user per month, all billed annually with a three-user minimum, plus a custom-quoted Enterprise Plus tier for the largest organizations; monthly billing carries a roughly 25 to 40 percent premium over annual pricing across these tiers. A free Individual plan with limited storage is also available for personal use. Box integrates with major productivity and business software including Microsoft 365, Google Workspace, Salesforce, and Slack, and offers additional paid add-ons such as Box Shield for threat detection, Box Governance for retention and legal hold, and Box KeySafe for customer-managed encryption keys. Competitors in Box's market include Dropbox, Microsoft OneDrive and SharePoint, and Google Drive, though Box differentiates itself by focusing specifically on enterprise content governance, security, and workflow needs rather than general consumer file sync.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '6b78ba61-e23d-473a-8f61-939c1f5fce7b';

